(11028540, 'Grupa Pracuj', 'Grupa Pracuj is an HR Tech company that connects job seekers with employers and provides recruitment and employee development services. They offer innovative solutions, including AI-driven job matching, to help businesses streamline their hiring processes. Their clients range from small enterprises to large corporations across various industries, seeking effective talent acquisition and management strategies.', 'Poland', 'PL', '🇵🇱', 'https://pracujwgp.pl', 590, 'Public', 216.112205, 0.100567, 859.42735, 97.524778, 0.451269, 3.9768, 8.8124, 9.9036, true, 0),
(5280480, 'Amadeus Fire', 'Amadeus Fire is a staffing agency specializing in recruitment and placement services in the commercial and IT sectors. They connect businesses with qualified candidates, offering services such as interim management and IT freelancing. Their clientele includes various companies seeking efficient hiring solutions. With over 20 locations across Germany, they leverage their regional presence to understand local job markets better.', 'Germany', 'DE', '🇩🇪', 'https://amadeus-fire.de', 1135, 'Public', 414.856692, -0.036945, 429.383608, 49.033186, 0.118193, 1.035, 8.757, 30.8672, true, 1),
(18285512, 'Eezy Oyj', 'Eezy is a staffing agency that provides a range of employment services, including personnel leasing, recruitment, and training. The company serves both businesses and individuals, facilitating job placements and workforce management. With a focus on various industries, Eezy aims to connect job seekers with suitable employment opportunities while assisting companies in finding qualified personnel.', 'Finland', 'FI', '🇫🇮', 'https://eezy.fi', 666, 'Public', 158.977055, -0.174395, 74.01089, 10.536858, 0.066279, 0.4655, 7.024, 175.791, true, 2),
(501430, 'FDM Group', 'FDM Group is a consulting firm specializing in tech and business talent solutions. They provide training and development programs to help individuals build careers in technology while assisting businesses in enhancing productivity and innovation through skilled talent. Their services include consulting and project delivery, focusing on bridging the digital skills gap for their clients.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://fdmgroup.com', 4145, 'Public', 234.926658, -0.186373, 173.62768, 24.179097, 0.102922, 0.7391, 7.1809, 9.9668, true, 3),
(5174553, 'Ogunsen AB', 'Ogunsen AB is a consulting and recruitment firm specializing in providing expert services in talent acquisition and management. They focus on helping organizations find qualified specialists and leaders, particularly in finance and related fields. With a commitment to sustainability and diversity, Ogunsen aims to enhance the effectiveness of their clients'' workforce and contribute to a more inclusive labor market.', 'Sweden', 'SE', '🇸🇪', 'https://ogunsen.se', 10, 'Public', 45.78848, -0.042821, 33.932719, 2.966432, 0.064786, 0.7411, 11.4389, 18.0383, true, 4),
(40865279, 'PageGroup', 'PageGroup is a recruitment agency specializing in providing talent solutions for organizations. They offer services such as executive search and recruitment outsourcing, helping businesses find qualified candidates across various industries. With a global presence, PageGroup focuses on changing lives by connecting people with job opportunities.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://page.com', 2106, 'Public', 2110.419342, -0.070838, 1105.167123, 103.288578, 0.048942, 0.5237, 10.6998, 40.0711, true, 5),
(8675714, 'Robert Walters', 'Robert Walters is a recruitment agency that specializes in connecting businesses with top talent across various sectors including accounting, finance, legal, and technology. The company provides tailored recruitment solutions and talent advisory services to help organizations find the right candidates and assist individuals in their job search. With a strong presence in the UK, Robert Walters operates through multiple offices to serve its clients effectively.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://robertwalters.co.uk', 4508, 'Public', 1032.489224, -0.107742, 173.503661, 10.57472, 0.010242, 0.168, 16.4074, -9.0524, true, 6),
(8454443, 'Hays', 'Hays is a recruitment agency specializing in qualified, professional, and skilled recruitment. The company connects jobseekers with employers across various industries, providing services such as recruitment process outsourcing and executive search. With a global presence and a diverse range of expertise, Hays supports both candidates and businesses in navigating the labor market effectively.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://haysplc.com', 31439, 'Public', 8733.39688, 0.000915, 1689.713518, 103.367888, 0.011836, 0.1935, 16.3466, 81.9428, true, 7),
(12444477, 'Brunel', 'Brunel is a recruitment agency specializing in workforce solutions across various industries including Conventional Energy, Mining, and Life Sciences. The company connects skilled professionals with businesses seeking talent, offering services such as contract hire, direct hire, and consulting solutions. Brunel operates globally, providing tailored support to enhance operational efficiency for its clients.', 'Netherlands', 'NL', '🇳🇱', 'https://brunel.net', 5307, 'Public', 1389.308966, 0.010006, 460.954473, 50.992231, 0.036703, 0.3318, 9.0397, 23.4707, true, 8),
(5161314, 'NGS Group', 'NGS Group AB is a recruitment agency specializing in executive search, staffing, and interim management services. They cater to businesses and organizations in various sectors, including healthcare and social services, by providing expert recruitment solutions to meet their staffing needs. NGS Group operates through a network of specialists and has a strong presence in the Nordic market.', 'Sweden', 'SE', '🇸🇪', 'https://ngsgroup.se', 368, 'Public', 29.25088, -0.208695, 8.151364, 0.434112, 0.014841, 0.2787, 18.7771, -182.5547, true, 9),
(8895426, 'PION Group AB', 'PION Group AB is a consulting and recruitment firm that specializes in maximizing organizational performance through strategic consulting and skilled recruitment services. They operate under various brands, providing expertise in IT, tech, and human resources to businesses and organizations across Sweden, Norway, and Finland.', 'Sweden', 'SE', '🇸🇪', 'https://piongroup.se', 20, 'Public', 146.068352, -0.12173, 29.121721, 2.79072, 0.019106, 0.1994, 10.4352, -50.3126, true, 10),
(3595177, 'Ework Group', 'Ework Group is a talent solutions provider specializing in connecting businesses with skilled professionals across various industries. They offer services such as consulting, recruitment, and total talent management, helping organizations optimize their workforce and project execution. With a strong network of professionals, Ework Group supports clients in navigating the complexities of talent acquisition and management.', 'Sweden', 'SE', '🇸🇪', 'https://eworkgroup.com', 548, 'Public', 1420.219837, -0.050862, 184.706521, 19.307235, 0.013595, 0.1301, 9.5667, 14.5376, true, 11),
(10889877, 'Randstad', 'Randstad is an HR services company that specializes in staffing solutions and workforce management. It connects businesses with qualified talent across various industries, including logistics, healthcare, and professional services. Randstad offers services such as temporary staffing, permanent recruitment, and HR consulting to help organizations manage their workforce effectively.', 'Netherlands', 'NL', '🇳🇱', 'https://randstad.com', 60315, 'Public', 26330.16469, -0.057551, 8194.727789, 964.11965, 0.036617, 0.3112, 8.4997, 13.6027, true, 12),
(2446778, 'Adecco', 'Adecco is a recruitment agency that specializes in staffing solutions for businesses and job seekers. The company offers services such as temporary and permanent placement, training, and outsourcing to help organizations manage their workforce effectively. Adecco serves a diverse range of industries, providing tailored solutions to meet the unique needs of its clients.', 'Switzerland', 'CH', '🇨🇭', 'https://adecco.com', 205090, 'Public', 26507.911193, -0.005775, 7939.941663, 931.371456, 0.035136, 0.2995, 8.525, 11.5809, true, 13),
(7215898, 'Synergie France', 'Synergie is an employment agency specializing in temporary staffing, recruitment, and HR consulting services. They serve businesses across various sectors, providing tailored solutions for workforce management and recruitment challenges. With a network of agencies, Synergie connects qualified candidates with job opportunities while supporting companies in their hiring processes.', 'France', 'FR', '🇫🇷', 'https://synergie.fr', 4773, 'Public', 3698.111964, 0.03587, NULL, 153.339522, 0.041464, 0.1291, 3.1141, 4.3016, false, 14),
(1477589, 'Staffline Recruitment Limited', 'Staffline Recruitment Limited is a recruitment agency that specializes in providing staffing solutions for various industries, including logistics, manufacturing, and food production. The company connects businesses with qualified candidates for temporary, permanent, and fixed-term positions, addressing the workforce needs of its clients. Staffline operates through a network of branches and onsite services across the UK and Ireland.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://staffline.co.uk', 2396, 'Public', 1462.880328, 0.05574, NULL, 21.017256, 0.014367, 0.0517, 3.6013, 4.4046, false, 15),
(1335665, 'Empresaria Group plc', 'Empresaria Group plc is a staffing agency that operates across six diversified sectors, including Professional, IT, Healthcare, and Offshore Services. The company provides tailored recruitment solutions to businesses, helping them find exceptional talent to meet their operational needs. With a presence in multiple countries, Empresaria is committed to positively impacting the lives of people through its staffing services.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://empresaria.com', 130, 'Public', 315.91976, -0.029297, NULL, 15.994264, 0.050628, 0.1516, 2.9934, 7.874, false, 16),
(3593079, 'Gattaca', 'Gattaca PLC is a recruitment agency specializing in STEM sectors, providing talent solutions for engineering and technology companies. They help businesses tackle workforce challenges by connecting them with skilled professionals. Gattaca operates in various industries, including aerospace and energy, and focuses on delivering project management and consulting services to meet client needs.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://gattacaplc.com', 244, 'Public', 527.281976, -0.004121, NULL, 5.430119, 0.010298, 0.0302, 2.9305, 4.4636, false, 17),
(2122004, 'Freelance.com', 'Freelance.com is a talent management service that connects businesses with freelancers and small to medium enterprises. It offers solutions for sourcing talent, managing payroll, and providing administrative support, catering to the needs of organizations seeking flexible workforce solutions. The company operates a digital platform that facilitates project management and training services for its users.', 'France', 'FR', '🇫🇷', 'https://freelance.com', 2466, 'Public', 1200.985021, 0.095712, NULL, 32.64087, 0.027178, 0.1388, 5.1085, 6.3618, false, 18),
(1177943, 'RTC Group Plc', 'RTC Group Plc is a recruitment agency that specializes in providing staffing solutions for both white and blue-collar positions across various sectors, including engineering, construction, and transportation. The company operates through its brands, such as ATA Recruitment and Ganymede, to deliver tailored recruitment services to businesses and organizations in need of qualified personnel.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://rtcgroupplc.co.uk', 21, 'Public', 126.28595, 0.099347, NULL, 4.347532, 0.034426, 0.1125, 3.267, 4.1328, false, 19),
(3391652, 'SThree', 'SThree is a consultancy specializing in STEM workforce solutions, connecting skilled professionals with organizations in need of expertise in science, technology, engineering, and mathematics. The company operates through various specialist brands, providing recruitment and strategic consulting services to businesses across multiple sectors, including life sciences and financial services.', 'United Kingdom (UK)', 'UK', '🇬🇧', 'https://sthree.com', 7883, 'Public', 1721.305335, -0.073894, NULL, 59.852915, 0.034772, 0.1779, 5.1162, 8.3924, false, 20);
