insert into public.valuation_assumptions (id, subject_company, basis_label, ebitda_fy2026e, ebitda_currency, company_weight, as_of_label, methodology) values
(1, 'Michelscom', 'FY2026E EBITDA', 2.62, 'EUR', 50, 'June 2026', 'Indicative Enterprise Value derived as FY2026E EBITDA multiplied by EV/EBITDA multiples observed across a screen of listed recruitment & HR-services peers and precedent transactions. Scenarios: Low = lower quartile; Median & Average = base case; Upside = midpoint of upper quartile and maximum; Max = highest observed multiple. An optional size adjustment discounts the multiples of size-outlier comps only. Figures are indicative, on a cash-free / debt-free basis, and do not constitute a fairness opinion or formal valuation.');
